        const records = await lookup(host, { all: true, verbatim: true });
        for (const r of records) {
          if (r.family === 4 && isPrivateIpv4(r.address)) throw …;
          if (r.family === 6 && ipv6IsPrivate(new Address6(r.address))) throw …;
        }
      }
    }
